code.Java:
import java.io.*;
import java.util.*;

public class Main {
    private static long isqrt(long x){
        long r = (long)Math.sqrt((double)x);
        while ((r+1)*(r+1) <= x) ++r;
        while (r*r > x) --r;
        return r;
    }
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            long[] a = new long[N];
            for (int i = 0; i < N; i++) a[i] = fs.nextLong();
            long ops = 0;
            for (int i = N - 2; i >= 0; i--) {
                while (a[i] > a[i+1] && a[i] > 1) {
                    a[i] = isqrt(a[i]);
                    ops++;
                }
            }
            sb.append(ops).append('\n');
        }
        System.out.print(sb.toString());
    }
    // Fast scanner for large input
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in){ this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException {
            int c; do { c = readByte(); } while (c <= ' ');
            boolean neg = false;
            if (c == '-') { neg = true; c = readByte(); }
            long val = 0;
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return neg ? -val : val;
        }
        int nextInt() throws IOException { return (int)nextLong(); }
    }
}

code.Python3:
import sys, math

def isqrt(x: int) -> int:
    return int(math.isqrt(x))

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        a = [int(next(it)) for _ in range(N)]
        ops = 0
        for i in range(N-2, -1, -1):
            while a[i] > a[i+1] and a[i] > 1:
                a[i] = isqrt(a[i])
                ops += 1
        out_lines.append(str(ops))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

