const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
function next(){return input[idx++];}
if (input.length===0){process.exit(0);} 
const T = Number(next());
let outputs = [];
for(let t=0;t<T;t++){
  const N = Number(next());
  let a = new Array(N);
  for(let i=0;i<N;i++) a[i] = BigInt(next());
  let ops = 0n;
  for(let i=N-2;i>=0;i--){
    while(a[i] > a[i+1] && a[i] > 1n){
      // integer sqrt for BigInt
      let x = a[i];
      let r = BigInt(Math.floor(Math.sqrt(Number(x)))); // safe because x <= 1e18 fits Number
      while ((r+1n)*(r+1n) <= x) r++;
      while (r*r > x) r--;
      a[i] = r;
      ops++;
    }
  }
  outputs.push(ops.toString());
}
console.log(outputs.join('\n'));

